dec:
display: flex;
  flex-direction: column;
  gap: var(--doc-heading-spacing-after);
  /* Fallback layout behavior if alignment isn't centered */
  text-align: left;

font-family: var(--doc-font-paragraph-heading);
  font-size: var(--doc-heading-size);
  font-weight: var(--doc-heading-weight);
  color: var(--doc-primary-color);
  margin: 0;
  line-height: 1.2;

font-family: var(--doc-font-header);
  font-size: var(--doc-header-size);
  color: var(--doc-secondary-color);
  display: flex;
  align-items: center;
  gap: 0.5rem;

border: 0;
  height: var(--doc-table-border);
  background-color: var(--doc-lines-color);
  margin-top: var(--doc-heading-spacing-after);
  margin-bottom: 0;
